⟦Γ:Rules⟧{
  ∀b:Board,p:Position: isValidMove(b,p)⇔grid[p.row][p.col]=empty ∧ 0≤p.row≤2 ∧ 0≤p.col≤2

  winCondition(b,player)≡∃line∈{rows,cols,diagonals}:allEqual(line,player)

  ∀b:Board: b.currentPlayer=X ⇒ lastPlayer=O

  ∀b:Board: ¬(xWins(b) ∧ oWins(b))

  boardFull(b)≡∀(r,c)∈[0,2]×[0,2]:b.grid[r][c]≠empty
}

⟦Λ:Funcs⟧{
  isGameOver≜λ(b).gameState(b)≠inProgress

  gameState≜λ(b).{
    xWins(b)⇒xWins |
    oWins(b)⇒oWins |
    boardFull(b)⇒draw |
    else⇒inProgress
  }

  xWins≜λ(b).winCondition(b,X)

  oWins≜λ(b).winCondition(b,O)

  winCondition≜λ(b,p).∃r∈[0,2]:(∀c∈[0,2]:b.grid[r][c]=p) ∨ ∃c∈[0,2]:(∀r∈[0,2]:b.grid[r][c]=p) ∨ (∀i∈[0,2]:b.grid[i][i]=p) ∨ (∀i∈[0,2]:b.grid[i][2−i]=p)

  boardFull≜λ(b).∀r,c∈[0,2]:b.grid[r][c]≠empty
