  TransactionType≜{deposit, withdraw}
  Result≜{success:Boolean, newBalance:Float, message:String}
}

⟦Γ:Rules⟧{
  ∀a:Account: balance(a) ≥ 0.0
  ∀t:Transaction: type(t)=withdraw ⇒ amount(t) ≤ 10000.0
  ∀a:Account ∀t:Transaction: type(t)=withdraw ⇒ (amount(t) ≤ balance(a) ∧ balance(a) - amount(t) ≥ 0.0)
  ∀a:Account ∀t:Transaction: type(t)=deposit ⇒ amount(t) > 0.0
}

⟦Λ:Funcs⟧{
  deposit≜λ(account:Account, amount:Float).
    (amount > 0.0) ⇒ {
      account.balance ← account.balance + amount;
      return Result{success:True, newBalance:account.balance, message:"Deposit successful"}
    } ∨ return Result{success:False, newBalance:account.balance, message:"Invalid amount"}

  withdraw≜λ(account:Account, amount:Float).
    (amount > 0.0 ∧ amount ≤ 10000.0 ∧ amount ≤ account.balance) ⇒ {
      account.balance ← account.balance - amount;
      return Result{success:True, newBalance:account.balance, message:"Withdrawal successful"}
    } ∨ (amount > 10000.0) ⇒ return Result{success:False, newBalance:account.balance, message:"Exceeds maximum withdrawal limit"}
    ∨ (amount > account.balance) ⇒ return Result{success:False, newBalance:account.balance, message:"Insufficient balance"}
    ∨ return Result{success:False, newBalance:account.balance, message:"Invalid amount"}
}

