𝔸1.0.task-scheduler@2026-02-27
γ≔task-management

⟦Ω:Meta⟧{
  sender≜@system
  receiver≜@scheduler
  intent≜inform
  id≜"ts-spec-001"
  timestamp≜1740681600
  protocol≜1
}

⟦Σ:Types⟧{
  Task≜{id:String, priority:ℤ∈[1,5], deadline:Timestamp, status:TaskStatus}
  TaskStatus≜{unassigned,assigned,completed,failed}
  Worker≜{id:String, assigned_task:Task∨nil, capacity:ℕ}
  Timestamp≜ℕ
  TaskQueue≜{t|∀t:Task}
  WorkerPool≜{w|∀w:Worker}
}

⟦Γ:Rules⟧{
  ∀t∈TaskQueue: priority(t)∈{1,2,3,4,5}
  ∀t∈TaskQueue: deadline(t)>0

  ∀w∈WorkerPool: assigned_task(w)∈Task ∨ assigned_task(w)=nil
  ∀t∈TaskQueue: (status(t)=assigned) ⇒ (∃!w∈WorkerPool: assigned_task(w)=t)

  ∀w₁,w₂∈WorkerPool: w₁≠w₂ ⇒ assigned_task(w₁)≠assigned_task(w₂)

  ∀t₁,t₂∈TaskQueue: (status(t₁)=unassigned ∧ status(t₂)=unassigned ∧ priority(t₁)>priority(t₂)) 
    ⇒ (assign(t₁) before assign(t₂))

  ∀w∈WorkerPool: (assigned_task(w)≠nil) ⇒ (capacity(w)>0)
}

⟦Λ:Funcs⟧{
  nextHighestPriority≜λ(tasks,workers).
    let U≜{t∈tasks | status(t)=unassigned}
    let A≜{w∈workers | assigned_task(w)=nil}
    if U=∅ ∨ A=∅ then nil
    else argmax_{t∈U}(priority(t))

  assignTask≜λ(t,w,tasks,workers).
    (status(t)≠unassigned ∨ assigned_task(w)≠nil) ⇒ ERROR
    ∧ tasks'≜tasks[status(t):=assigned]
    ∧ workers'≜workers[assigned_task(w):=t]

  isFeasible≜λ(tasks,workers).
    |{t∈tasks | status(t)=unassigned}| ≤ |{w∈workers | assigned_task(w)=nil}|
}

⟦Ε⟧⟨δ≜0.80;φ≜100;τ≜◊⁺⟩
